def build(d):
    c = ""
    for s in d["steps"]:
        si = str(s["id"])
        h = "<div class=card id=s" + si + "><div class=hdr><span class=tag>Step " + si + "</span><h3>" + s["label"] + "</h3></div>"
        if s["type"] == "user":
            wc = str(s["words"])
            h += "<details><summary>" + chr(128203) + " " + wc + chr(23383) + "</summary><div class=txt>" + s["text"] + "</div></details>"
        else:
            for f in s["feedback"]:
                h += "<div class=fb><b>" + f[0] + "</b><br>" + f[1] + "</div>"
        h += "</div>"
        c += h
    tl = "".join("<li><a href=#s" + str(s["id"]) + ">" + s["label"] + "</a></li>" for s in d["steps"])
    s = d["summary"]
    d_amt = s["last_words"] - s["first_words"]
    df = "".join("<li>" + d + "</li>" for d in s["differences"])
    t = d["title"]
    return ("<!DOCTYPE html><html lang=zh-CN><head><meta charset=UTF-8><title>" + t + "</title><style>" + CSS + "</style></head><body>"
        + "<nav class=side><h2>" + "流程" + "</h2><ul>" + tl + "</ul></nav>"
        + "<main class=main><h1>" + t + "</h1><p class=sub>Hermes Agent</p>" + c
        + "<section class=sum><h2>" + "最终总结" + "</h2>"
        + "<div class=meter><div><div class=num>" + str(s["first_words"]) + "</div><div class=lbl>" + s["first_title"] + "</div></div>"
        + "<div class=arr>&rarr; +" + str(d_amt) + chr(23383) + "</div>"
        + "<div><div class=num>" + str(s["last_words"]) + "</div><div class=lbl>" + s["last_title"] + "</div></div></div>"
        + "<ul class=diff>" + df + "</ul></section></main></body></html>")

def main():
    os.makedirs(OUTPUT_DIR, exist_ok=True)
    p = os.path.join(OUTPUT_DIR, "上下文管理测试.html")
    with open(p, "w", encoding="utf-8") as f:
        f.write(build(DATA))
    sz = os.path.getsize(p)
    print(chr(10004) + " " + p + " (" + str(sz) + " bytes)")

if __name__ == "__main__":
    main()
